<template>
  <transition name="el-fade-in-linear">
    <div v-if="visible" class="container">
      <div class="verify-wrapper" v-loading="loading">
        <p class="title"><span>拖动下方滑块完成拼图</span><i class="el-icon-circle-close" @click="close"></i></p>
        <div class="verify">
          <div class="verify--canvas" ref="canvas" :style="{ width: `${width}px`, height: `${height}px` }">
            <canvas ref="bgCanvas" v-show="!loading"></canvas>
            <canvas
              v-show="!loading"
              class="block_canvas"
              ref="blockCanvas"
              @mousedown.prevent="(e) => drag(e, 'blockCanvas', 'circle')"
              @touchstart="
                (e) => {
                  terminal = 'mobile';
                  drag(e, 'blockCanvas', 'circle');
                }
              "
            ></canvas>
          </div>

          <div class="verify--slider">
            <div
              class="circle"
              ref="circle"
              @mousedown.prevent="(e) => drag(e, 'circle', 'blockCanvas')"
              @touchstart="
                (e) => {
                  terminal = 'mobile';
                  drag(e, 'circle', 'blockCanvas');
                }
              "
            >
              <div class="arrow" :class="{ 'is-touch': isTouch }"></div>
            </div>
          </div>

          <div class="verify--operational">
            <i class="el-icon-refresh-right" @click="handleRefresh"></i>
          </div>
        </div>
      </div>
    </div>
  </transition>
</template>
<script>
const l = 42; // 滑块边长
const r = 9; // 滑块圆半径
const PI = Math.PI;
const L = l + r * 2 + 3; // 滑块实际边长

const Y = 70; // 滑块Y轴距离

export default {
  name: 'FvSliderVerify',
  data() {
    return {
      eventLock: false,
      terminal: 'pc',
      blkTilesW: null,
      isTouch: false,
      bgRandom: 0,
      loading: false,
    };
  },
  props: {
    visible: {
      type: Boolean,
      default: false,
    },
    width: {
      type: Number,
      default: 300,
    },
    height: {
      type: Number,
      default: 180,
    },
    imgs: {
      type: Array,
      default: () => [],
    },
    successMsg: {
      type: String,
      default: '验证通过',
    },
    failMsg: {
      type: String,
      default: '请正确拼合图像',
    },
  },
  watch: {
    visible(newVal) {
      if (newVal) {
        this.$nextTick(() => {
          this.initCanvas();
        });
      }
    },
  },
  methods: {
    close() {
      if (this.eventLock) return;
      this.$emit('update:visible', false);
    },
    initCanvas() {
      this.eventLock = false;
      this.loading = true;

      const bgCanvas = this.$refs.bgCanvas;
      const bgCtx = bgCanvas.getContext('2d');

      const block_canvas = this.$refs.blockCanvas;
      const blockCtx = block_canvas.getContext('2d');

      const random = (max, min) => {
        return Math.floor(Math.random() * (min - max) + max);
      };

      const bgRandom = random(0, this.imgs.length > 0 ? this.imgs.length : 2);
      const img = new Image();
      img.crossOrigin = 'Anonymous';
      img.src = this.imgs.length > 0 ? this.imgs[bgRandom] : require(`./images/${bgRandom}.png`);
      img.onerror = () => {
        img.src = require('./images/error.png');
      };

      const width = this.width;
      const height = this.height;

      /**
       * 滑块随机受控图形区间内 x轴
       * L + 10 滑块边长 + 10px间隙
       */
      const blkTilesW = random(L + 10, width - (L + 10));
      this.blkTilesW = blkTilesW;

      bgCanvas.width = width;
      bgCanvas.height = height;
      block_canvas.width = width;
      block_canvas.height = height;

      img.onload = () => {
        this.loading = false;

        this.draw(bgCtx, { x: blkTilesW, y: Y, r: r }, 'fill');
        this.draw(blockCtx, { x: blkTilesW, y: Y, r: r }, 'clip');

        bgCtx.drawImage(img, 1, 1, width, height);
        blockCtx.drawImage(img, 0, 0, width, height);

        // 提取滑块放至左侧 并重置滑块画布宽度
        const y = Y - r * 2 - 1;
        const ImageData = blockCtx.getImageData(blkTilesW - 3, y, L, L);
        block_canvas.width = L;
        blockCtx.putImageData(ImageData, 0, y);
      };
    },
    drag(event, targetId, linkageId) {
      if (this.eventLock) return;

      this.isTouch = true;
      const targetDom = this.$refs[targetId];
      const linkageDom = this.$refs[linkageId];
      const terminal = this.terminal;

      let x = 0;
      const move = (moveEV) => {
        if (terminal === 'pc') {
          x = moveEV.x - event.x;
        } else {
          x = moveEV.changedTouches[0].clientX - event.changedTouches[0].clientX;
        }
        /**
         * 滑块拖动限定
         *
         */
        if (x >= this.width - L || x <= -2) return false;
        targetDom.style.left = x + 'px';
        linkageDom.style.left = x + 'px';
      };

      const up = () => {
        this.isTouch = false;
        document.removeEventListener('mousemove', move);
        document.removeEventListener('mouseup', up);

        document.removeEventListener('touchmove', move);
        document.removeEventListener('touchend', up);

        // 图块契合度 左右5 偏差
        const intervalMax = this.blkTilesW + 5;
        const intervalMin = this.blkTilesW - 5;

        let isSuccess = false;
        if (x >= intervalMin && x <= intervalMax) {
          isSuccess = true;
          this.eventLock = true;
          this.$emit('success');
        } else {
          isSuccess = false;
        }

        let loadingInstance = this.$loading({
          target: this.$refs.canvas,
          text: isSuccess ? this.successMsg : this.failMsg,
          spinner: isSuccess ? 'el-icon-check' : 'el-icon-close',
        });
        if (!isSuccess) {
          setTimeout(() => {
            loadingInstance.close();
            targetDom.style.left = 0;
            linkageDom.style.left = 0;
            this.initCanvas();
          }, 500);
        } else {
          setTimeout(() => {
            if (!isSuccess) {
              this.close();
            }
          }, 2000);
        }
      };

      if (terminal === 'pc') {
        document.addEventListener('mousemove', move);
        document.addEventListener('mouseup', up);
      } else {
        document.addEventListener('touchmove', move);
        document.addEventListener('touchend', up);
      }
    },
    draw(ctx, xy, type) {
      const x = xy.x,
        y = xy.y;
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.arc(x + l / 2, y - r + 2, r, 0.72 * PI, 2.26 * PI);
      ctx.lineTo(x + l, y);
      ctx.arc(x + l + r - 2, y + l / 2, r, 1.21 * PI, 2.78 * PI);
      ctx.lineTo(x + l, y + l);
      ctx.lineTo(x, y + l);
      ctx.arc(x + r - 2, y + l / 2, r + 0.4, 2.76 * PI, 1.24 * PI, true);
      ctx.lineTo(x, y);
      ctx.lineWidth = 1;
      ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.7)';
      ctx.stroke();
      ctx.globalCompositeOperation = 'destination-over';
      type === 'fill' ? ctx.fill() : ctx.clip();
    },
    handleRefresh() {
      if (this.eventLock) return;
      this.initCanvas();
    },
  },
};
</script>
